CREATE TABLE IF NOT EXISTS t_p97754588_arte_deli_site.promos (id SERIAL PRIMARY KEY, code VARCHAR(50) UNIQUE, title VARCHAR(100) NOT NULL, description TEXT, type VARCHAR(30) NOT NULL, value INTEGER DEFAULT 0, min_order INTEGER DEFAULT 0, is_active BOOLEAN DEFAULT TRUE, is_one_time BOOLEAN DEFAULT FALSE, for_new_users BOOLEAN DEFAULT FALSE, for_birthday BOOLEAN DEFAULT FALSE, emoji VARCHAR(10) DEFAULT '✨', created_at TIMESTAMPTZ DEFAULT NOW())
